let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  if (typeof rawTags === 'string') {
    return rawTags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(rawTags)) {
    return rawTags.map(t => t.toLowerCase());
  }
  return [];
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>}
 */
function loadProblems() {
  if (!cachedProblems) {
    const filePath = path.join(__dirname, '..', '..', 'data', 'problems.json');
    const content = fs.readFileSync(filePath, 'utf8');
    cachedProblems = JSON.parse(content);
  }
  return cachedProblems;
}

/**
 * Filter problems by difficulty, tags, and components.
 * @param {Array<Object>} problems
 * @param {Object} filters
 * @param {string} filters.difficulty
 * @param {Array<string>} filters.tags
 * @param {Array<string>} filters.components
 * @returns {Array<Object>}
 */
function filterProblems(problems, { difficulty, tags, components }) {
  return problems.filter(p => {
    if (difficulty && difficulty !== 'all' && p.difficulty !== difficulty) {
      return false;
    }
    if (tags && tags.length > 0) {
      const problemTags = (p.tags || []).map(t => t.toLowerCase());
      if (!tags.every(t => problemTags.includes(t))) {
        return false;
      }
    }
    if (components && components.length > 0) {
      if (!components.includes(p.component)) {
        return false;
      }
    }
    return true;
  });
}

